You just worked on this task:

TASK: `split_csv.js` handles simple rows. Add support for doubled-quote escaping with a custom `;` delimiter (non-RFC), verified by the added cases.

This is the implementation that was produced (the working source file). Do NOT run or test anything — base your briefing only on reading this code:

```js
module.exports = function splitCsv(line) {
  const out = [];
  let cur = '', q = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (q) {
      if (ch === '"') { if (line[i + 1] === '"') { cur += '"'; i++; } else q = false; }
      else cur += ch;
    } else if (ch === '"') q = true;
    else if (ch === ';') { out.push(cur); cur = ''; }
    else cur += ch;
  }
  out.push(cur);
  return out;
};

```

